import numpy as np

def measure_ai_human_calibration(
    ai_judge,
    calibration_set: list[dict],   # {'prompt', 'chosen', 'rejected', 'human_label'}
) -> dict:
    """
    Compute calibration: does AI confidence predict agreement with humans?
    Pairs binned by confidence; each bin shows agreement rate.
    """
    bins = {(0.5, 0.6): [], (0.6, 0.7): [], (0.7, 0.8): [], (0.8, 0.9): [], (0.9, 1.0): []}

    for item in calibration_set:
        result = ai_judge.judge(item['prompt'], item['chosen'], item['rejected'])
        ai_label = result["label"]
        conf = result["confidence"]
        agrees = (ai_label == item['human_label'])
        for (lo, hi), acc_list in bins.items():
            if lo <= conf < hi:
                acc_list.append(agrees)
                break

    return {
        f'{lo:.1f}-{hi:.1f}': {
            'agreement': np.mean(v) if v else None,
            'count': len(v),
        }
        for (lo, hi), v in bins.items()
    }
# Well-calibrated: bins at 0.7 should show ~70% agreement with humans.

def evaluate_reward_model(
    reward_model,
    test_pairs: list[dict],    # {'prompt', 'chosen', 'rejected', 'source'}
) -> dict:
    """
    Compute accuracy (fraction of pairs where RM scores chosen > rejected).
    Break down by source label (human vs ai) to see quality difference.
    """
    by_source = {}
    for pair in test_pairs:
        source = pair.get('source', 'unknown')
        r_chosen = reward_model.score(pair['prompt'], pair['chosen'])
        r_rejected = reward_model.score(pair['prompt'], pair['rejected'])
        correct = (r_chosen > r_rejected)
        by_source.setdefault(source, []).append(correct)

    return {
        source: {
            'accuracy': sum(v) / len(v),
            'count': len(v),
        }
        for source, v in by_source.items()
    }

# Expected: RLHF-labeled test pairs show higher RM accuracy than
# AI-labeled test pairs on expert domains, similar accuracy on general tasks.
